content.problemStatement:
What will be the output of the following C program?

```c
#include
// Function declaration using pointers (for pass by reference)
void modifyValues(int *x, int *y);

int main() {
    int a = 4;
    int b = 9;

    printf("Before function call: a = %d, b = %d\n", a, b);

    modifyValues(&a, &b);  // Passing addresses of a and b

    printf("After function call: a = %d, b = %d\n", a, b);

    return 0;
}

// Function definition using pointers
void modifyValues(int *x, int *y) {
    *x = *x + 10;  // Dereferencing pointer to modify original value
    *y = *y / 3;
    printf("Inside function: x = %d, y = %d\n", *x, *y);
}
```

